// src/utils/encryption.js
import CryptoJS from 'crypto-js';
import { NativeModules, Platform } from 'react-native';
import * as Keychain from 'react-native-keychain';

class EncryptionService {
  constructor() {
    this._sessionKey = null;
    this._initialized = false;
  }

  async initialize() {
    if (this._initialized) return;
    this._sessionKey = this._generateSessionKey();
    this._initialized = true;
  }

  _generateSessionKey() {
    const randomBytes = CryptoJS.lib.WordArray.random(32);
    return randomBytes.toString(CryptoJS.enc.Hex);
  }

  encrypt(data) {
    if (!this._sessionKey) {
      throw new Error('EncryptionService not initialized');
    }
    const iv = CryptoJS.lib.WordArray.random(16);
    const encrypted = CryptoJS.AES.encrypt(
      JSON.stringify(data),
      CryptoJS.enc.Hex.parse(this._sessionKey),
      {
        iv: iv,
        mode: CryptoJS.mode.GCM || CryptoJS.mode.CBC,
        padding: CryptoJS.pad.Pkcs7,
      }
    );
    return {
      ciphertext: encrypted.toString(),
      iv: iv.toString(CryptoJS.enc.Hex),
      tag: encrypted.tag ? encrypted.tag.toString(CryptoJS.enc.Hex) : null,
    };
  }

  decrypt(encryptedData) {
    if (!this._sessionKey) {
      throw new Error('EncryptionService not initialized');
    }
    const decrypted = CryptoJS.AES.decrypt(
      encryptedData.ciphertext,
      CryptoJS.enc.Hex.parse(this._sessionKey),
      {
        iv: CryptoJS.enc.Hex.parse(encryptedData.iv),
        mode: CryptoJS.mode.GCM || CryptoJS.mode.CBC,
        padding: CryptoJS.pad.Pkcs7,
      }
    );
    return JSON.parse(decrypted.toString(CryptoJS.enc.Utf8));
  }

  maskCardNumber(cardNumber) {
    const cleaned = cardNumber.replace(/\s/g, '');
    if (cleaned.length < 8) return '****';
    return `****${cleaned.slice(-4)}`;
  }

  maskSensitiveData(data) {
    const masked = { ...data };
    if (masked.cardNumber) {
      masked.cardNumber = this.maskCardNumber(masked.cardNumber);
    }
    if (masked.cvv) {
      masked.cvv = '***';
    }
    if (masked.pin) {
      masked.pin = '****';
    }
    return masked;
  }

  async storeSecurely(key, value) {
    try {
      const encrypted = this.encrypt(value);
      await Keychain.setGenericPassword(key, JSON.stringify(encrypted), {
        service: `payment_${key}`,
        accessControl: Keychain.ACCESS_CONTROL.BIOMETRY_ANY_OR_DEVICE_PASSCODE,
        accessible: Keychain.ACCESSIBLE.WHEN_UNLOCKED_THIS_DEVICE_ONLY,
      });
      return true;
    } catch (error) {
      console.error('Secure storage error:', error);
      return false;
    }
  }

  async retrieveSecurely(key) {
    try {
      const credentials = await Keychain.getGenericPassword({
        service: `payment_${key}`,
      });
      if (credentials) {
        const encryptedData = JSON.parse(credentials.password);
        return this.decrypt(encryptedData);
      }
      return null;
    } catch (error) {
      console.error('Secure retrieval error:', error);
      return null;
    }
  }

  async deleteSecurely(key) {
    try {
      await Keychain.resetGenericPassword({ service: `payment_${key}` });
      return true;
    } catch (error) {
      console.error('Secure deletion error:', error);
      return false;
    }
  }

  destroy() {
    this._sessionKey = null;
    this._initialized = false;
  }
}

