// src/utils/biometric.js
import ReactNativeBiometrics, { BiometryTypes } from 'react-native-biometrics';

class BiometricService {
  constructor() {
    this.rnBiometrics = new ReactNativeBiometrics({ allowDeviceCredentials: true });
  }

  async isAvailable() {
    try {
      const { available, biometryType } = await this.rnBiometrics.isSensorAvailable();
      return {
        available,
        type: biometryType,
        isFaceId: biometryType === BiometryTypes.FaceID,
        isTouchId: biometryType === BiometryTypes.TouchID,
        isBiometrics: biometryType === BiometryTypes.Biometrics,
      };
    } catch (error) {
      return { available: false, type: null, error: error.message };
    }
  }

  async authenticate(promptMessage = 'Confirm payment') {
    try {
      const { available } = await this.isAvailable();
      if (!available) {
        return { success: false, error: 'Biometric authentication not available' };
      }

      const { success } = await this.rnBiometrics.simplePrompt({
        promptMessage,
        cancelButtonText: 'Cancel',
        fallbackPromptMessage: 'Use passcode',
      });

      return { success };
    } catch (error) {
      return { success: false, error: error.message };
    }
  }

  async createSignature(payload, promptMessage = 'Sign transaction') {
    try {
      const { keysExist } = await this.rnBiometrics.biometricKeysExist();
      if (!keysExist) {
        await this.rnBiometrics.createKeys();
      }

      const { success, signature } = await this.rnBiometrics.createSignature({
        promptMessage,
        payload,
      });

      return { success, signature };
    } catch (error) {
      return { success: false, error: error.message };
    }
  }
}

