export default BiometricService;


// src/utils/validation.js
export class PaymentValidator {
  static validateCardNumber(number) {
    const cleaned = number.replace(/\s|-/g, '');

    if (!/^\d{13,19}$/.test(cleaned)) {
      return { valid: false, error: 'Invalid card number length' };
    }

    // Luhn algorithm
    let sum = 0;
    let isEven = false;
    for (let i = cleaned.length - 1; i >= 0; i--) {
      let digit = parseInt(cleaned[i], 10);
      if (isEven) {
        digit *= 2;
        if (digit > 9) digit -= 9;
      }
      sum += digit;
      isEven = !isEven;
    }

    const valid = sum % 10 === 0;
    return {
      valid,
      error: valid ? null : 'Invalid card number',
      cardType: valid ? this.getCardType(cleaned) : null,
    };
  }

  static getCardType(number) {
    const patterns = {
      visa: /^4/,
      mastercard: /^(5[1-5]|2[2-7])/,
      amex: /^3[47]/,
      discover: /^(6011|65|64[4-9])/,
      diners: /^(30[0-5]|36|38)/,
      jcb: /^35/,
    };

    for (const [type, pattern] of Object.entries(patterns)) {
      if (pattern.test(number)) return type;
    }
    return 'unknown';
  }

  static validateExpiry(month, year) {
    const m = parseInt(month, 10);
    const y = parseInt(year, 10);

    if (isNaN(m) || isNaN(y) || m < 1 || m > 12) {
      return { valid: false, error: 'Invalid expiry date' };
    }

    const fullYear = y < 100 ? 2000 + y : y;
    const expiry = new Date(fullYear, m, 0);
    const now = new Date();

    const valid = expiry > now;
    return {
      valid,
      error: valid ? null : 'Card has expired',
    };
  }

  static validateCVV(cvv, cardType = 'visa') {
    const length = cardType === 'amex' ? 4 : 3;
    const regex = new RegExp(`^\\d{${length}}$`);
    const valid = regex.test(cvv);
    return {
      valid,
      error: valid ? null : `CVV must be ${length} digits`,
    };
  }

  static validateAmount(amount) {
    const num = parseFloat(amount);
    if (isNaN(num) || num <= 0) {
      return { valid: false, error: 'Invalid amount' };
    }
    if (num > 999999.99) {
      return { valid: false, error: 'Amount exceeds maximum limit' };
    }
    return { valid: true, error: null };
  }

  static validateEmail(email) {
    const regex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    const valid = regex.test(email);
    return { valid, error: valid ? null : 'Invalid email address' };
  }

  static sanitizeInput(input) {
    if (typeof input !== 'string') return input;
    return input
      .replace(/<[^>]*>/g, '')
      .replace(/[<>'"`;]/g, '')
      .trim();
  }
}


// src/services/TransactionLogger.js
class TransactionLogger {
  constructor() {
    this._logs = [];
    this._maxLogs = 1000;
  }

  log(event, data = {}) {
    const entry = {
      id: this._generateId(),
      timestamp: new Date().toISOString(),
      event,
      data: this._sanitizeLogData(data),
    };

    this._logs.push(entry);
    if (this._logs.length > this._maxLogs) {
      this._logs = this._logs.slice(-this._maxLogs);
    }

    if (__DEV__) {
      console.log(`[PaymentLog] ${event}`, entry.data);
    }
  }

  _sanitizeLogData(data) {
    const sanitized = { ...data };
    const sensitiveKeys = ['cardNumber', 'cvv', 'pin', 'token', 'secret', 'password'];
    for (const key of sensitiveKeys) {
      if (sanitized[key]) {
        sanitized[key] = '[REDACTED]';
      }
    }
    return sanitized;
  }

  _generateId() {
    return `txlog_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;
  }

  getRecentLogs(count = 50) {
    return this._logs.slice(-count);
  }

  getLogsByEvent(event) {
    return this._logs.filter((log) => log.event === event);
  }

  clear() {
    this._logs = [];
  }
}

export const transactionLogger = new TransactionLogger();
export default TransactionLogger;


